// ====================================================================
// AGENCY PROFITABILITY CALCULATOR
// Analyzes client profitability with proper cost allocation
// ====================================================================

// Configuration
const CONFIG = {
  platformFeeRate: 0.029,      // 2.9% payment processor fee
  monthlySoftwareCosts: 500,   // Monthly SaaS costs
  overheadRate: 0.30,          // 30% overhead on time costs
  minProfitMargin: 20,         // Minimum acceptable profit margin %
  maxTimeRatio: 40             // Maximum acceptable time/revenue ratio %
};

const allInputs = $input.all();

// Initialize metrics
const metrics = {
  totalAdSpend: 0,
  facebookAdSpend: 0,
  googleAdSpend: 0,
  totalRevenue: 0,
  totalConversions: 0,
  facebookConversions: 0,
  totalTimeCost: 0,
  totalBillableHours: 0
};

// Track data sources for validation
const dataSources = {
  facebook: false,
  google: false,
  shopify: false,
  timeTracking: false
};

// Client-level tracking
const clients = {};

const errors = [];
const warnings = [];

// Process each input
for (const item of allInputs) {
  const json = item.json;

  // Facebook Ads
  if (json.data && Array.isArray(json.data)) {
    dataSources.facebook = true;
    json.data.forEach(ad => {
      const spend = parseFloat(ad.spend) || 0;
      const accountName = ad.account_name || 'Unknown Client';

      // Initialize client if needed
      if (!clients[accountName]) {
        clients[accountName] = {
          name: accountName,
          adSpend: 0,
          revenue: 0,
          timeCost: 0,
          billableHours: 0,
          conversions: 0,
          platforms: { facebook: 0, google: 0 }
        };
      }

      clients[accountName].adSpend += spend;
      clients[accountName].platforms.facebook += spend;
      metrics.totalAdSpend += spend;
      metrics.facebookAdSpend += spend;

      // Count conversions
      if (ad.conversions) {
        ad.conversions.forEach(conv => {
          if (conv.action_type === 'purchase') {
            const convValue = parseFloat(conv.value) || 0;
            metrics.totalConversions += convValue;
            metrics.facebookConversions += convValue;
            clients[accountName].conversions += convValue;
          }
        });
      }

      // Calculate revenue from ROAS
      if (ad.purchase_roas) {
        ad.purchase_roas.forEach(roas => {
          if (roas.action_type === 'purchase') {
            const revenue = spend * (parseFloat(roas.value) || 0);
            metrics.totalRevenue += revenue;
            clients[accountName].revenue += revenue;
          }
        });
      }
    });
  }

  // Google Ads
  if (json.results && Array.isArray(json.results)) {
    dataSources.google = true;
    json.results.forEach(campaign => {
      if (campaign.metrics) {
        const spend = (campaign.metrics.costMicros || 0) / 1000000;
        const campaignName = campaign.campaign?.name || 'Unknown Campaign';

        // Try to map to client (simplified - you may need better mapping logic)
        const clientName = 'Google Ads Client';

        if (!clients[clientName]) {
          clients[clientName] = {
            name: clientName,
            adSpend: 0,
            revenue: 0,
            timeCost: 0,
            billableHours: 0,
            conversions: 0,
            platforms: { facebook: 0, google: 0 }
          };
        }

        clients[clientName].adSpend += spend;
        clients[clientName].platforms.google += spend;
        metrics.totalAdSpend += spend;
        metrics.googleAdSpend += spend;

        if (campaign.metrics.conversions) {
          const convValue = parseFloat(campaign.metrics.conversions) || 0;
          metrics.totalConversions += convValue;
          clients[clientName].conversions += convValue;
        }

        if (campaign.metrics.conversionValue) {
          const revenue = (campaign.metrics.conversionValue || 0) / 1000000;
          metrics.totalRevenue += revenue;
          clients[clientName].revenue += revenue;
        } else {
          warnings.push('Google Ads conversion value missing - CAC may be inaccurate');
        }
      }
    });
  }

  // Shopify Orders (use as primary revenue source)
  const facebookRevenue = metrics.totalRevenue;
  if (json.orders && Array.isArray(json.orders)) {
    dataSources.shopify = true;
    let shopifyRevenue = 0;
    json.orders.forEach(order => {
      const totalPrice = parseFloat(order.total_price) || 0;
      const refunds = parseFloat(order.total_refunds) || 0;
      shopifyRevenue += (totalPrice - refunds);
    });

    // Check for revenue discrepancy
    if (facebookRevenue > 0 && shopifyRevenue > 0) {
      const diff = Math.abs(shopifyRevenue - facebookRevenue);
      const diffPercent = (diff / Math.max(shopifyRevenue, facebookRevenue)) * 100;
      if (diffPercent > 10) {
        warnings.push(`Revenue mismatch: Shopify ($${shopifyRevenue.toFixed(2)}) vs Facebook ($${facebookRevenue.toFixed(2)}) - ${diffPercent.toFixed(1)}% difference`);
      }
    }

    // Use Shopify revenue if higher (more accurate)
    if (shopifyRevenue > metrics.totalRevenue) {
      metrics.totalRevenue = shopifyRevenue;
    }
  }

  // Time Tracking
  if (json.json && Array.isArray(json.json)) {
    dataSources.timeTracking = true;
    json.json.forEach(entry => {
      const costAmount = parseFloat(entry.costAmount) || 0;
      const hours = parseFloat(entry.hours) || 0;
      const clientName = entry.clientName || 'Unknown Client';
      const revenueAttributed = parseFloat(entry.revenueAttributed) || 0;

      // Initialize client if needed
      if (!clients[clientName]) {
        clients[clientName] = {
          name: clientName,
          adSpend: 0,
          revenue: 0,
          timeCost: 0,
          billableHours: 0,
          conversions: 0,
          platforms: { facebook: 0, google: 0 }
        };
      }

      clients[clientName].timeCost += costAmount;
      clients[clientName].revenue += revenueAttributed;

      metrics.totalTimeCost += costAmount;
      metrics.totalRevenue += revenueAttributed;

      if (entry.billable) {
        metrics.totalBillableHours += hours;
        clients[clientName].billableHours += hours;
      }
    });
  }
}

// Validate data completeness
if (!dataSources.facebook && !dataSources.google) {
  errors.push('No ad platform data found');
}
if (!dataSources.shopify && metrics.totalRevenue === 0) {
  errors.push('No revenue data found');
}
if (!dataSources.timeTracking) {
  warnings.push('No time tracking data - labor costs may be incomplete');
}

// Calculate costs
const platformFees = metrics.totalRevenue * CONFIG.platformFeeRate;
const overheadAllocation = metrics.totalTimeCost * CONFIG.overheadRate;
const totalCosts = metrics.totalAdSpend + metrics.totalTimeCost + platformFees + 
                   CONFIG.monthlySoftwareCosts + overheadAllocation;

// Calculate key metrics
const cac = metrics.totalConversions > 0 ? metrics.totalAdSpend / metrics.totalConversions : 0;
const roas = metrics.totalAdSpend > 0 ? metrics.totalRevenue / metrics.totalAdSpend : 0;
const grossProfit = metrics.totalRevenue - totalCosts;
const profitMargin = metrics.totalRevenue > 0 ? (grossProfit / metrics.totalRevenue) * 100 : 0;
const timeRatio = metrics.totalRevenue > 0 ? (metrics.totalTimeCost / metrics.totalRevenue) * 100 : 0;

// Determine risk level
let riskLevel = '🟢 HEALTHY';
let riskReasons = [];

if (profitMargin < 0) {
  riskLevel = '🔴 CRITICAL';
  riskReasons.push('negative profit margin');
} else if (profitMargin < CONFIG.minProfitMargin) {
  riskLevel = '⚠️ WARNING';
  riskReasons.push(`low profit margin (${profitMargin.toFixed(1)}%)`);
}

if (timeRatio > CONFIG.maxTimeRatio) {
  if (riskLevel === '🟢 HEALTHY') riskLevel = '⚠️ WARNING';
  riskReasons.push(`high time ratio (${timeRatio.toFixed(1)}%)`);
}

if (roas < 2.0 && metrics.totalAdSpend > 0) {
  if (riskLevel === '🟢 HEALTHY') riskLevel = '⚠️ WARNING';
  riskReasons.push(`low ROAS (${roas.toFixed(2)}x)`);
}

// Calculate client-level metrics
const clientDetails = [];
const numClients = Object.keys(clients).length;
const softwarePerClient = numClients > 0 ? CONFIG.monthlySoftwareCosts / numClients : 0;

Object.values(clients).forEach(client => {
  const clientPlatformFees = client.revenue * CONFIG.platformFeeRate;
  const clientOverhead = client.timeCost * CONFIG.overheadRate;
  const clientTotalCosts = client.adSpend + client.timeCost + clientPlatformFees + 
                           softwarePerClient + clientOverhead;

  const clientProfit = client.revenue - clientTotalCosts;
  const clientMargin = client.revenue > 0 ? (clientProfit / client.revenue) * 100 : 0;
  const clientTimeRatio = client.revenue > 0 ? (client.timeCost / client.revenue) * 100 : 0;
  const clientROAS = client.adSpend > 0 ? client.revenue / client.adSpend : 0;

  // Determine client risk level
  let clientRisk = '🟢 HEALTHY';
  let clientRiskReasons = [];

  if (clientMargin < 0) {
    clientRisk = '🔴 CRITICAL';
    clientRiskReasons.push('negative margin');
  } else if (clientMargin < CONFIG.minProfitMargin) {
    clientRisk = '⚠️ WARNING';
    clientRiskReasons.push('low margin');
  }

  if (clientTimeRatio > CONFIG.maxTimeRatio) {
    if (clientRisk === '🟢 HEALTHY') clientRisk = '⚠️ WARNING';
    clientRiskReasons.push('high time cost');
  }

  if (clientROAS < 2.0 && client.adSpend > 0) {
    if (clientRisk === '🟢 HEALTHY') clientRisk = '⚠️ WARNING';
    clientRiskReasons.push('low ROAS');
  }

  clientDetails.push({
    name: client.name,
    revenue: parseFloat(client.revenue.toFixed(2)),
    costs: {
      adSpend: parseFloat(client.adSpend.toFixed(2)),
      timeCost: parseFloat(client.timeCost.toFixed(2)),
      platformFees: parseFloat(clientPlatformFees.toFixed(2)),
      software: parseFloat(softwarePerClient.toFixed(2)),
      overhead: parseFloat(clientOverhead.toFixed(2)),
      total: parseFloat(clientTotalCosts.toFixed(2))
    },
    profit: parseFloat(clientProfit.toFixed(2)),
    profitMargin: parseFloat(clientMargin.toFixed(2)),
    timeRatio: parseFloat(clientTimeRatio.toFixed(2)),
    roas: parseFloat(clientROAS.toFixed(2)),
    billableHours: parseFloat(client.billableHours.toFixed(2)),
    conversions: client.conversions,
    platforms: client.platforms,
    riskLevel: clientRisk,
    riskReasons: clientRiskReasons.join(', ')
  });
});

// Sort clients by profit margin (worst first for attention)
clientDetails.sort((a, b) => a.profitMargin - b.profitMargin);

// Create summary text for Slack header
const summaryEmoji = profitMargin >= CONFIG.minProfitMargin ? '✅' : profitMargin >= 0 ? '⚠️' : '🔴';
const summary_text = `${summaryEmoji} *Revenue:* $${metrics.totalRevenue.toFixed(0)} | *Profit:* $${grossProfit.toFixed(0)} (${profitMargin.toFixed(1)}%) | *ROAS:* ${roas.toFixed(2)}x | ${riskLevel}`;

// Return comprehensive data
return [{
  json: {
    // Summary for Slack
    summary_text: summary_text,

    // Client breakdown for AI analysis
    clientDetails: clientDetails,

    // Detailed metrics for AI analysis
    summary: {
      totalRevenue: parseFloat(metrics.totalRevenue.toFixed(2)),
      grossProfit: parseFloat(grossProfit.toFixed(2)),
      profitMargin: parseFloat(profitMargin.toFixed(2)),
      riskLevel: riskLevel,
      riskReasons: riskReasons.join(', '),
      roas: parseFloat(roas.toFixed(2)),
      cac: parseFloat(cac.toFixed(2)),
      timeRatio: parseFloat(timeRatio.toFixed(2))
    },

    breakdown: {
      costs: {
        adSpend: parseFloat(metrics.totalAdSpend.toFixed(2)),
        timeCost: parseFloat(metrics.totalTimeCost.toFixed(2)),
        platformFees: parseFloat(platformFees.toFixed(2)),
        software: CONFIG.monthlySoftwareCosts,
        overhead: parseFloat(overheadAllocation.toFixed(2)),
        total: parseFloat(totalCosts.toFixed(2))
      },
      adPlatforms: {
        facebook: parseFloat(metrics.facebookAdSpend.toFixed(2)),
        google: parseFloat(metrics.googleAdSpend.toFixed(2))
      },
      efficiency: {
        billableHours: parseFloat(metrics.totalBillableHours.toFixed(2)),
        conversions: metrics.totalConversions,
        avgRevenuePerHour: metrics.totalBillableHours > 0 ? 
          parseFloat((metrics.totalRevenue / metrics.totalBillableHours).toFixed(2)) : 0
      }
    },

    dataValidation: {
      errors: errors,
      warnings: warnings,
      sourcesFound: dataSources
    }
  }
}];
